      concept_sunrise_desc: 'Zero Hour \u092A\u094D\u0930\u093E\u0915\u0943\u0924\u093F\u0915 \u0926\u093F\u0928 \u0915\u094B \u091F\u094D\u0930\u0948\u0915 \u0915\u0930\u0924\u093E \u0939\u0948\u0964 \u091C\u092C \u0938\u0942\u0930\u094D\u092F \u0909\u0917\u0924\u093E \u0939\u0948, \u0938\u092E\u093E\u0928\u093E\u0902\u0924\u0930 \u0918\u0921\u093C\u0940 \u0936\u0941\u0930\u0942 \u0939\u094B\u0924\u0940 \u0939\u0948\u0964 ZHT 0 \u0938\u0941\u092C\u0939 \u0915\u0947 \u0928\u091C\u0926\u0940\u0915 \u0939\u0948, \u091C\u093F\u0938\u0938\u0947 \u0926\u093F\u0928 \u0915\u0940 \u0936\u0941\u0930\u0941\u0906\u0924 \u0926\u0943\u0936\u094D\u092F \u0930\u094B\u0936\u0928\u0940 \u0938\u0947 \u092E\u0947\u0932 \u0916\u093E\u0924\u0940 \u0939\u0948\u0964',
