      map_heading: '\u062E\u0631\u064A\u0637\u0629 <span class="accent">Zero Hour</span> \u0627\u0644\u062D\u0627\u0644\u064A\u0629',
      concept_heading: '<span class="accent">\u0627\u0644\u0645\u0641\u0647\u0648\u0645</span>',
      concept_subtitle: '\u0645\u0639\u0638\u0645 \u0627\u0644\u062D\u064A\u0648\u0627\u0646\u0627\u062A \u0639\u0644\u0649 \u0643\u0648\u0643\u0628 \u0627\u0644\u0623\u0631\u0636 \u062A\u0646\u0627\u0645 \u0644\u064A\u0644\u064B\u0627 \u0648\u062A\u0633\u062A\u064A\u0642\u0638 \u0637\u0628\u064A\u0639\u064A\u064B\u0627 \u0639\u0646\u062F \u0627\u0644\u0641\u062C\u0631. \u0627\u0644\u0645\u062C\u062A\u0645\u0639 \u0627\u0644\u0628\u0634\u0631\u064A \u0641\u0631\u0636 \u0639\u0644\u0649 \u0646\u0641\u0633\u0647 \u0646\u0638\u0627\u0645\u064B\u0627 \u0645\u062E\u062A\u0644\u0641\u064B\u0627 \u2014 \u0648\u0647\u0648 \u0644\u064A\u0633 \u0637\u0628\u064A\u0639\u064A\u064B\u0627 \u0648\u0644\u0627 \u0635\u062D\u064A\u064B\u0627 \u0648\u0644\u0627 \u0636\u0631\u0648\u0631\u064A\u064B\u0627.',
      concept_sunrise_title: '\u0645\u0631\u062A\u0628\u0637 \u0628\u0634\u0631\u0648\u0642 \u0627\u0644\u0634\u0645\u0633',
      concept_sunrise_desc: '\u064A\u062A\u062A\u0628\u0639 Zero Hour \u0627\u0644\u064A\u0648\u0645 \u0627\u0644\u0637\u0628\u064A\u0639\u064A. \u0639\u0646\u062F\u0645\u0627 \u062A\u0634\u0631\u0642 \u0627\u0644\u0634\u0645\u0633\u060C \u062A\u0628\u062F\u0623 \u0627\u0644\u0633\u0627\u0639\u0629 \u0627\u0644\u0645\u0648\u0627\u0632\u064A\u0629. ZHT 0 \u0645\u062C\u0627\u0648\u0631 \u0644\u0644\u0641\u062C\u0631\u060C \u0645\u0645\u0627 \u064A\u062C\u0639\u0644 \u0628\u062F\u0627\u064A\u0629 \u0627\u0644\u064A\u0648\u0645 \u062A\u062A\u0648\u0627\u0641\u0642 \u0645\u0639 \u0636\u0648\u0621 \u0627\u0644\u0646\u0647\u0627\u0631.',
      concept_parallel_title: '\u0646\u0638\u0627\u0645 \u0645\u0648\u0627\u0632\u0650',
      concept_parallel_desc: '\u064A\u0638\u0644 \u0627\u0644\u062A\u0648\u0642\u064A\u062A \u0627\u0644\u0645\u062F\u0646\u064A \u0627\u0644\u0639\u0627\u062F\u064A \u062F\u0648\u0646 \u062A\u063A\u064A\u064A\u0631 \u0644\u0644\u0646\u0642\u0644 \u0648\u0627\u0644\u0628\u0631\u0645\u062C\u064A\u0627\u062A \u0648\u0627\u0644\u0642\u0627\u0646\u0648\u0646 \u0648\u0627\u0644\u0637\u064A\u0631\u0627\u0646 \u0648\u0627\u0644\u0645\u0627\u0644\u064A\u0629. Zero Hour \u0645\u0648\u062C\u0648\u062F \u0628\u062C\u0627\u0646\u0628\u0647 \u0643\u0637\u0628\u0642\u0629 \u062C\u062F\u0648\u0644\u0629 \u0645\u0631\u0643\u0632\u0647\u0627 \u0627\u0644\u0625\u0646\u0633\u0627\u0646.',
      concept_drift_title: '\u0627\u0646\u0632\u064A\u0627\u062D \u0645\u0648\u0633\u0645\u064A \u0633\u0644\u0633',
      concept_drift_desc: '\u0628\u062F\u0644\u064B\u0627 \u0645\u0646 \u0635\u062F\u0645\u0629 \u0627\u0644\u0633\u0627\u0639\u0629 \u0627\u0644\u0645\u0641\u0627\u062C\u0626\u0629 \u0644\u0644\u062A\u0648\u0642\u064A\u062A \u0627\u0644\u0635\u064A\u0641\u064A\u060C \u064A\u0646\u0632\u0627\u062D Zero Hour \u0628\u0627\u0633\u062A\u0645\u0631\u0627\u0631 \u0645\u0639 \u0627\u0644\u0641\u0635\u0648\u0644\u060C \u0645\u062A\u0628\u0639\u064B\u0627 \u062D\u0631\u0643\u0629 \u0627\u0644\u0634\u0645\u0633 \u0627\u0644\u0637\u0628\u064A\u0639\u064A\u0629.',
      concept_schedule_title: '\u062C\u062F\u0648\u0644\u0629 \u0637\u0628\u064A\u0639\u064A\u0629',
      concept_schedule_desc: '\u064A\u0645\u0643\u0646 \u0627\u0644\u062A\u0639\u0628\u064A\u0631 \u0639\u0646 \u0627\u0644\u062D\u064A\u0627\u0629 \u0627\u0644\u064A\u0648\u0645\u064A\u0629 \u0628\u0640 Zero Time. \u00AB\u0627\u0644\u0645\u062F\u0631\u0633\u0629 \u062A\u0628\u062F\u0623 \u0641\u064A ZHT 1.5\u00BB \u062A\u0639\u0646\u064A \u0633\u0627\u0639\u0629 \u0648\u0646\u0635\u0641 \u0628\u0639\u062F \u0627\u0644\u0634\u0631\u0648\u0642. \u0627\u0644\u0645\u062D\u0644\u0627\u062A \u062A\u0641\u062A\u062D \u0641\u064A ZHT 2. \u0628\u062F\u064A\u0647\u064A \u0648\u0639\u0627\u0644\u0645\u064A.',
      concept_disruption_title: '\u0635\u0641\u0631 \u0627\u0636\u0637\u0631\u0627\u0628',
