      concept_subtitle: '\u0411\u0456\u043B\u044C\u0448\u0456\u0441\u0442\u044C \u0442\u0432\u0430\u0440\u0438\u043D \u043D\u0430 \u043F\u043B\u0430\u043D\u0435\u0442\u0456 \u0417\u0435\u043C\u043B\u044F \u0441\u043F\u043B\u044F\u0442\u044C \u0432\u043D\u043E\u0447\u0456 \u0442\u0430 \u043F\u0440\u043E\u043A\u0438\u0434\u0430\u044E\u0442\u044C\u0441\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u043D\u043E \u043D\u0430 \u0441\u0432\u0456\u0442\u0430\u043D\u043A\u0443. \u041B\u044E\u0434\u0441\u044C\u043A\u0435 \u0441\u0443\u0441\u043F\u0456\u043B\u044C\u0441\u0442\u0432\u043E \u043D\u0430\u0432\u2019\u044F\u0437\u0430\u043B\u043E \u0441\u043E\u0431\u0456 \u0456\u043D\u0448\u0443 \u0441\u0438\u0441\u0442\u0435\u043C\u0443 \u2014 \u0446\u0435 \u043D\u0435 \u043F\u0440\u0438\u0440\u043E\u0434\u043D\u043E, \u043D\u0435 \u043A\u043E\u0440\u0438\u0441\u043D\u043E \u0456 \u043D\u0435 \u043D\u0435\u043E\u0431\u0445\u0456\u0434\u043D\u043E.',
